    '["Боль в суставе при бросках — стоп-сигнал","Диффузная мышечная усталость допустима, боль в самом суставе — нет"]',
    '["Не пропускайте поддерживающие упражнения даже на хорошем самочувствии","Возвращайтесь к нагрузке поэтапно, без рывков","Психологическая готовность так же важна, как физическая"]',
    '["Боль в суставе при бросках","Возврат ощущения «мёртвой руки» (внезапная слабость и потеря контроля)","Потеря скорости или контроля броска вместе с болью"]',
    '[{"q":"Почему возврат к метаниям так нескоро?","a":"Верхней губе и месту крепления бицепса нужно много времени, чтобы выдержать мощные бросковые нагрузки. Поэтому возврат идёт поэтапно: сначала дальние броски, затем с горки, и только потом соревновательные — обычно через 7–9 месяцев."},{"q":"Кто решает, что я готов к спорту?","a":"Решение принимают вместе с куратором и хирургом по совокупности: сила (обычно не менее 90% от здоровой руки), безболезненные движения, качество механики и достаточный срок после операции."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_slap
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев. Фазы 1–6 включены
--    (терминальная фаза 6 несёт критерии возврата к спорту/метаниям).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; объём/градусы/сила/соотношения → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (покой и защита → восстановление подвижности)
  (1, 'passive_elevation_90_p1', 'Пассивный подъём руки не менее 90°',                                                        'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_30_p1',        'Пассивный поворот руки наружу с локтем у тела не менее 30°',                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'full_elbow_rom_p1',       'Полное пассивное сгибание и разгибание локтя',                                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'muscle_contraction_p1',   'Мышцы плеча и лопатки включаются при пальпации (оценка куратора)',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (1, 'pain_wound_ok_p1',        'Боль под контролем, нет признаков воспаления раны',                                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль под контролем и нет признаков воспаления раны (покраснение, выделения)?', 'Сравните с тем, как было в первые дни после операции', 50::smallint, TRUE),
  (1, 'no_complications_p1',     'Нет осложнений этого этапа (оценка куратора)',                                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление подвижности → раннее укрепление и активные движения)
  (2, 'passive_elevation_120_p2','Пассивный подъём руки не менее 120°',                                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_er_45_p2',        'Пассивный поворот руки наружу не менее 45°',                                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'pain_le_4_p2',            'Боль не более 4 из 10',                                                                     'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'min_compensation_p2',     'Минимум компенсаций при движениях с помощью (оценка куратора)',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (2, 'sleep_ok_p2',            'Сон без частых пробуждений от боли',                                                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается спать без частых пробуждений от боли?', 'Оцените по нескольким последним ночам', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (раннее укрепление → продвинутое укрепление)
  (3, 'full_passive_rom_p3',     'Полный безболезненный пассивный объём движений по подъёму руки и повороту наружу',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'ir_within_10_p3',         'Поворот руки внутрь — в пределах 10° от здоровой стороны',                                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'pain_le_4_p3',            'Боль не более 4 из 10',                                                                     'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'min_compensation_p3',     'Минимум компенсаций при активных движениях (оценка куратора)',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (3, 'no_painful_arc_p3',       'Нет болезненной дуги при активном отведении руки в сторону',                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 4 → Фаза 5 (продвинутое укрепление → позднее укрепление и подготовка к спорту)
  (4, 'full_painfree_rom_p4',    'Полный безболезненный объём движений (и пассивный, и активный)',                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'pain_le_2_p4',            'Боль не более 2 из 10',                                                                     'measurement',      'vas_score', 'pain', '<=', 2::numeric, NULL, 7::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'scapular_mechanics_p4',   'Симметричная работа лопатки во всех упражнениях (оценка куратора)',                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'negative_tests_p4',       'Отрицательные тесты на защемление и нестабильность (оценка куратора)',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (4, 'strength_er_ir_85_p4',    'Сила наружных и внутренних вращателей не менее 85% от здоровой руки',                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 5 → Фаза 6 (позднее укрепление → возврат к спорту и метаниям)
  (5, 'strength_er_ir_85_p5',    'Сила наружных и внутренних вращателей не менее 85% от здоровой руки (цель для спорта — не менее 90%)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'er_ir_ratio_60_p5',       'Соотношение силы наружных и внутренних вращателей не менее 60%',                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, FALSE),
  (5, 'negative_tests_p5',       'Отрицательные тесты на защемление и нестабильность (оценка куратора)',                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (5, 'scapular_mechanics_p5',   'Симметричная работа лопатки (оценка куратора)',                                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (5, 'questionnaires_p5',       'Заполнены опросники функции плеча (для документирования; единого порога нет — решает куратор очно)', 'self_report', NULL, NULL, NULL, NULL, NULL, 30::smallint, 'Заполнили опросники о том, как пользуетесь плечом в жизни?', 'Единого порога нет — это для документирования функции, решение принимает куратор', 50::smallint, FALSE),
  (5, 'surgeon_clearance_p5',    'Получено разрешение хирурга',                                                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 60::smallint, TRUE),

  -- Фаза 6 (терминальная) — критерии возврата к спорту / метаниям
  (6, 'isokinetic_er_torque_p6', 'Изокинетика: момент наружных вращателей относительно массы тела в диапазоне 18–23% (при скорости 180°/сек) — порог начала программы бросков', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, FALSE),
  (6, 'er_ir_ratio_66_76_p6',    'Соотношение силы наружных и внутренних вращателей в диапазоне 66–76% (при скорости 180°/сек; для финального возврата к игре — 72–76%)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, FALSE),
  (6, 'er_abduction_ratio_p6',   'Соотношение силы наружных вращателей к наружному отведению в диапазоне 67–75% (при скорости 180°/сек)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (6, 'strength_90_p6',          'Сила оперированного плеча не менее 90% от здоровой руки для возврата к спорту (≥75% — для допуска к продвинутым нагрузкам около 3 месяцев)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
  (6, 'no_pain_plyo_p6',         'Нет боли при наращивании прыжково-бросковых и интервальных программ',                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Прыжково-бросковые и интервальные нагрузки получаются без боли в суставе?', 'Оцените по пробным спорт-специфическим движениям', 50::smallint, TRUE),
  (6, 'full_throwers_rom_p6',    'Полный объём движений метателя, включая поворот наружу, при симметричной механике (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_slap' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
